fun getAppVersion(context: Context): String {
 return try {
 val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
 packageInfo.versionName
 } catch (e: Exception) {
 "N/A"
 }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SettingsScreen(navController: NavHostController) {
 val context = LocalContext.current
 val db = AppDatabase.getDatabase(context)
 val coroutineScope = rememberCoroutineScope()
 val deletedRecordsCount by db.attendanceDao().getAllDeletedRecords()
 .map { it.size }
 .collectAsState(initial = 0)
 val appVersion = remember { getAppVersion(context) }
 val backupFileName = "PresentMate_Backup.doc"

 var showPermissionRationaleDialog by remember { mutableStateOf(false) }

 val requestPermissionLauncher = rememberLauncherForActivityResult(
 contract = ActivityResultContracts.RequestPermission(),
 onResult = { isGranted: Boolean ->
 if (isGranted) {
 // Permission granted, proceed with export
 coroutineScope.launch {
 val recordsToExport = withContext(Dispatchers.IO) {
 db.attendanceDao().getAllRecordsNonFlow()
 }
 if (recordsToExport.isEmpty()) {
 Toast.makeText(context, "No records to export", Toast.LENGTH_SHORT).show()
 return@launch
 }
 val success = withContext(Dispatchers.IO) {
 DataExportUtils.exportAttendanceDataToDoc(context, recordsToExport, backupFileName)
 }
 if (success) {
 Toast.makeText(context, "Data exported to $backupFileName", Toast.LENGTH_LONG).show()
 } else {
 Toast.makeText(context, "Export failed", Toast.LENGTH_SHORT).show()
 }
 }
 } else {
 // Permission denied
 showPermissionRationaleDialog = true
 }
 }
 )

 fun launchExportProcess() {
 coroutineScope.launch {
 val recordsToExport = withContext(Dispatchers.IO) {
 db.attendanceDao().getAllRecordsNonFlow()
 }
 if (recordsToExport.isEmpty()) {
 Toast.makeText(context, "No records to export", Toast.LENGTH_SHORT).show()
 return@launch
 }
 val success = withContext(Dispatchers.IO) {
 DataExportUtils.exportAttendanceDataToDoc(context, recordsToExport, backupFileName)
 }
 if (success) {
 Toast.makeText(context, "Data exported to $backupFileName", Toast.LENGTH_LONG).show()
 } else {
 Toast.makeText(context, "Export failed", Toast.LENGTH_SHORT).show()
 }
 }
 }

 if (showPermissionRationaleDialog) {
 AlertDialog(
 onDismissRequest = { showPermissionRationaleDialog = false },
 title = { Text("Permission Required") },
 text = { Text("Storage permission is required to export data. Please grant the permission in app settings.") },
 confirmButton = {
 Button(
 onClick = {
 showPermissionRationaleDialog = false
 // Open app settings
 val intent = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS)
 val uri = Uri.fromParts("package", context.packageName, null)
 intent.data = uri
 context.startActivity(intent)
 }
 ) {
 Text("Open Settings")
 }
 },
 dismissButton = {
 Button(onClick = { showPermissionRationaleDialog = false }) {
 Text("Cancel")
 }
 }
 )
 }

 Column(
 modifier = Modifier
 .fillMaxSize()
 .padding(16.dp)
 .verticalScroll(rememberScrollState()),
 verticalArrangement = Arrangement.spacedBy(16.dp)
 ) {
 SettingsItem(
 title = "Recycle Bin",
 description = "$deletedRecordsCount items",
 icon = Icons.Default.DeleteOutline,
 onClick = {
 navController.navigate("recycleBin")
 }
 )
 Divider()
 SettingsItem(
 title = "App Version",
 description = appVersion,
 icon = Icons.Filled.Verified,
 onClick = { Toast.makeText(context, "App Version: $appVersion", Toast.LENGTH_SHORT).show() }
 )
 SettingsItem(
 title = "Help",
 description = "Find answers to your questions",
 icon = Icons.AutoMirrored.Filled.HelpOutline,
 onClick = { navController.navigate("helpScreen") }
 )
 SettingsItem(
 title = "Why Present Mate?",
 description = "Learn about the app's mission",
 icon = Icons.Outlined.Info,
 onClick = { navController.navigate("whyPresentMateScreen") }
 )
 Divider()
 SettingsItem(
 title = "Export Data",
 description = "Save records to $backupFileName",
 icon = Icons.Filled.FileUpload,
 onClick = {
 if (Build.VERSION.SDK_INT <= Build.VERSION_CODES.P) {
 when (ContextCompat.checkSelfPermission(context, Manifest.permission.WRITE_EXTERNAL_STORAGE)) {
 PackageManager.PERMISSION_GRANTED -> {
 launchExportProcess()
 }
 else -> {
 requestPermissionLauncher.launch(Manifest.permission.WRITE_EXTERNAL_STORAGE)
 }
 }
 } else {
 // For Android Q (API 29) and above, WRITE_EXTERNAL_STORAGE is not needed for getExternalFilesDir()
 launchExportProcess()
 }
 }
 )
 SettingsItem(
 title = "Import Data",
 description = "Restore records from $backupFileName",
 icon = Icons.Filled.FileDownload,
 onClick = {
 coroutineScope.launch {
 val importedRecords = withContext(Dispatchers.IO) {
 DataImportUtils.importAttendanceDataFromDoc(context, backupFileName)
 }
 if (importedRecords.isNotEmpty()) {
 withContext(Dispatchers.IO) {
 importedRecords.forEach { record -> db.attendanceDao().insertRecord(record) } // Reverted to insertRecord
 }
 Toast.makeText(context, "Data imported successfully from $backupFileName", Toast.LENGTH_LONG).show()
 } else {
 Toast.makeText(context, "Import failed or no data found in $backupFileName", Toast.LENGTH_LONG).show()
 }
 }
 }
 )
 }
}

@Composable
fun SettingsItem(
 modifier: Modifier = Modifier,
 title: String,
 description: String,
 icon: androidx.compose.ui.graphics.vector.ImageVector,
 onClick: () -> Unit,
 showArrow: Boolean = true
) {
 Card(
 modifier = modifier
 .fillMaxWidth()
 .clickable(onClick = onClick),
 shape = RoundedCornerShape(12.dp),
 elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
 ) {
 Row(
 modifier = Modifier
 .padding(horizontal = 16.dp, vertical = 20.dp),
 verticalAlignment = Alignment.CenterVertically,
 horizontalArrangement = Arrangement.SpaceBetween
 ) {
 Icon(imageVector = icon, contentDescription = title, tint = MaterialTheme.colorScheme.primary)
 Spacer(modifier = Modifier.width(16.dp))
 Column(modifier = Modifier.weight(1f)) {
 Text(text = title, style = MaterialTheme.typography.titleMedium)
 Text(text = description, style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant)
 }
 if (showArrow) {
 Icon(Icons.AutoMirrored.Filled.ArrowForwardIos, contentDescription = "Navigate")
 }
 }
 }
}
