ovements and fixes for your geofence tracking implementation.

Based on my analysis of your code, I've identified several issues and optimizations that would improve the geofence tracking functionality. Here are my recommendations:

## Issues with Current Implementation

1. **Session Management**: The current implementation handles only one ongoing session regardless of which geofence triggered it. The geofence ID isn't used to distinguish between different locations.

2. **PendingIntent Handling**: Multiple PendingIntents might be created inconsistently, and there's no unique identification.

3. **Error Handling**: Limited error handling in case of database operations or geofence failures.

4. **Debugging Visibility**: While logging exists, more specific logging would help with debugging.

## Recommended Fixes

### 1. Improve GeofenceBroadcastReceiver.kt

Here's an updated version with better session management:

```kotlin
class GeofenceBroadcastReceiver : BroadcastReceiver() {

 override fun onReceive(context: Context, intent: Intent) {
 val geofencingEvent = GeofencingEvent.fromIntent(intent)
 if (geofencingEvent?.hasError() == true) {
 Log.e("GeofenceReceiver", "Geofencing event has error: ${geofencingEvent.errorCode}")
 return
 }

 val geofenceTransition = geofencingEvent?.geofenceTransition
 val triggeringGeofences = geofencingEvent?.triggeringGeofences

 if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_ENTER) {
 Log.d("GeofenceReceiver", "Geofence Entered")
 triggeringGeofences?.forEach { geofence ->
 startSession(context, geofence.requestId)
 }
 } else if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_EXIT) {
 Log.d("GeofenceReceiver", "Geofence Exited")
 triggeringGeofences?.forEach { geofence ->
 endSession(context, geofence.requestId)
 }
 } else {
 Log.d("GeofenceReceiver", "Invalid transition type: $geofenceTransition")
 }
 }

 private fun startSession(context: Context, geofenceId: String) {
 val db = AppDatabase.getDatabase(context)
 CoroutineScope(Dispatchers.IO).launch {
 try {
 val now = System.currentTimeMillis()
 // Check if there's already an ongoing session
 val ongoingSession = db.attendanceDao().getOngoingSession()
 if (ongoingSession == null) {
 db.attendanceDao().insertRecord(
 AttendanceRecord(date = now, timeIn = now, timeOut = null)
 )
 Log.d("GeofenceReceiver", "Session started for geofence: $geofenceId")
 } else {
 Log.d("GeofenceReceiver", "Session already active for geofence: $geofenceId")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error starting session for geofence: $geofenceId", e)
 }
 }
 }

 private fun endSession(context: Context, geofenceId: String) {
 val db = AppDatabase.getDatabase(context)
 CoroutineScope(Dispatchers.IO).launch {
 try {
 val ongoingSession = db.attendanceDao().getOngoingSession()
 if (ongoingSession != null) {
 db.attendanceDao().updateRecord(
 ongoingSession.copy(timeOut = System.currentTimeMillis())
 )
 Log.d("GeofenceReceiver", "Session ended for geofence: $geofenceId")
 } else {
 Log.d("GeofenceReceiver", "No ongoing session to end for geofence: $geofenceId")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error ending session for geofence: $geofenceId", e)
 }
 }
 }
}
```

### 2. Improve GeofenceManager Class

Here's an improved version of the GeofenceManager with proper remove functionality:

```kotlin
class GeofenceManager(private val context: Context) {

 private val geofencingClient = LocationServices.getGeofencingClient(context)
 private val TAG = "GeofenceManager"

 fun addGeofence(
 id: String,
 latitude: Double,
 longitude: Double,
 radius: Float,
 pendingIntent: PendingIntent
 ) {
 if (ActivityCompat.checkSelfPermission(
 context,
 Manifest.permission.ACCESS_FINE_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Log.w(TAG, "Fine location permission not granted.")
 return
 }

 val geofence = Geofence.Builder()
 .setRequestId(id)
 .setCircularRegion(latitude, longitude, radius)
 .setExpirationDuration(Geofence.NEVER_EXPIRE)
 .setTransitionTypes(Geofence.GEOFENCE_TRANSITION_ENTER or Geofence.GEOFENCE_TRANSITION_EXIT)
 .build()

 val geofencingRequest = GeofencingRequest.Builder()
 .setInitialTrigger(GeofencingRequest.INITIAL_TRIGGER_ENTER)
 .addGeofence(geofence)
 .build()

 // Remove existing geofence first to avoid conflicts
 removeGeofence(pendingIntent) { 
 // After removal, add the new geofence
 geofencingClient.addGeofences(geofencingRequest, pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence added successfully for ID: $id")
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to add geofence for ID: $id", exception)
 }
 }
 }

 fun removeGeofence(pendingIntent: PendingIntent, callback: (() -> Unit)? = null) {
 geofencingClient.removeGeofences(pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence removed successfully.")
 callback?.invoke()
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to remove geofence.", exception)
 callback?.invoke() // Still try to add new geofence even if removal fails
 }
 }
}
```

### 3. Update GeofenceScreen.kt

The main activity/screen should properly manage the PendingIntent:

```kotlin
// Add this as a class property or as a remembered value to ensure consistency
