 Intent(context, GeofenceBroadcastReceiver::class.java),
 PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_MUTABLE
 )
}

// Update geofence when enabled and params change
LaunchedEffect(selectedSavedPlace, radiusMeters, isTrackingEnabled) {
 if (isTrackingEnabled && selectedSavedPlace != null) {
 selectedSavedPlace?.let {
 geofenceManager.addGeofence(
 it.id.toString(),
 it.latitude,
 it.longitude,
 radiusMeters,
 geofencePendingIntent // Use consistent PendingIntent
 )
 }
 }
}
```

## How to Verify Tracking is Working

1. **Check Logcat**: Look for the log messages in Logcat that start with "GeofenceReceiver" to verify that enter/exit events are being detected.

2. **Add Debug Logs**: You can add more detailed logging in the `addGeofence` method to verify that geofences are being registered.

3. **Test in Real Conditions**: Geofence accuracy can vary based on:
 - GPS signal quality
 - Device movement patterns
 - Geofence radius (50-100 meters is typically more reliable)
 - Location settings on the device

## Additional Recommendations

1. **Add Location Permission Checking**: Ensure you're properly checking and requesting location permissions.

2. **Battery Optimization**: Consider adding a foreground service for better reliability in the background.

3. **Database Query Improvements**: The current `getOngoingSession()` query might benefit from additional filtering if you plan to support multiple geofences.

