import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

// --- DAO --- //
@androidx.room.Dao
interface AttendanceDao {
 @androidx.room.Insert(onConflict = androidx.room.OnConflictStrategy.REPLACE)
 suspend fun insertRecord(record: AttendanceRecord)

 @androidx.room.Query("SELECT * FROM attendance_records ORDER BY date DESC")
 fun getAllRecords(): kotlinx.coroutines.flow.Flow<List<AttendanceRecord>>

 @androidx.room.Query("SELECT * FROM attendance_records ORDER BY date DESC") // Added for synchronous export
 fun getAllRecordsNonFlow(): List<AttendanceRecord> // Added for synchronous export

 @androidx.room.Query("SELECT * FROM attendance_records WHERE date = :date LIMIT 1")
 suspend fun getRecordByDate(date: Long): AttendanceRecord?

 @androidx.room.Update
 suspend fun updateRecord(record: AttendanceRecord)

 @androidx.room.Delete
 suspend fun deleteRecord(record: AttendanceRecord)

 @androidx.room.Insert(onConflict = androidx.room.OnConflictStrategy.REPLACE)
 suspend fun insertDeletedRecord(record: DeletedRecord)

 @androidx.room.Query("SELECT * FROM deleted_records ORDER BY deletedAt DESC")
 fun getAllDeletedRecords(): kotlinx.coroutines.flow.Flow<List<DeletedRecord>>

 @androidx.room.Query("DELETE FROM deleted_records WHERE id = :id")
 suspend fun permanentlyDeleteRecord(id: Int)

 @androidx.room.Query("SELECT * FROM attendance_records WHERE timeOut IS NULL ORDER BY timeIn DESC LIMIT 1")
 fun getOngoingSession(): AttendanceRecord?
}

// --- Database --- //
@Database(
 entities = [AttendanceRecord::class, DeletedRecord::class],
 version = 2, // Consider incrementing version if schema changed and no migration provided for new table/column, though just adding a query method is fine.
 exportSchema = false
)
abstract class AppDatabase : RoomDatabase() {
 abstract fun attendanceDao(): AttendanceDao

 companion object {
 @Volatile
 private var INSTANCE: AppDatabase? = null

 fun getDatabase(context: Context): AppDatabase {
 return INSTANCE ?: synchronized(this) {
 val instance = Room.databaseBuilder(
 context.applicationContext,
 AppDatabase::class.java,
 "attendance_database"
 ).fallbackToDestructiveMigration()
 .build()
 INSTANCE = instance
 instance
 }
 }
 }
}
"},{"role":"assistant","content":[{"type":"text","text":"Based on my analysis of the codebase, I can now provide comprehensive fixes for the geofence tracking implementation. Let me address all the issues you mentioned:

## Issues Identified

1. **PendingIntent Creation Inconsistency**: The app creates multiple PendingIntents with the same requestCode (0) and flags, which might lead to unexpected behavior.
2. **No Geofence Removal Before Adding**: When parameters change, the app doesn't remove the existing geofence before adding the new one.
3. **Limited Error Handling**: The BroadcastReceiver logs geofence errors but doesn't provide user feedback or retry mechanisms.
4. **Session Management**: The implementation only handles one ongoing session at a time and doesn't use geofence IDs properly.
5. **Permissions Handling**: Background location permissions require special handling on Android 10+.

## Recommended Fixes

### 1. Improved GeofenceBroadcastReceiver.kt

Let me create a complete, fixed version of this file:

```kotlin
package com.example.presentmate.geofence

import android.Manifest
import android.app.PendingIntent
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.util.Log
import android.widget.Toast
import androidx.core.app.ActivityCompat
import com.google.android.gms.location.Geofence
import com.google.android.gms.location.GeofencingEvent
import com.example.presentmate.db.AppDatabase
import com.example.presentmate.db.AttendanceRecord
import com.google.android.gms.location.GeofencingRequest
import com.google.android.gms.location.LocationServices
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class GeofenceBroadcastReceiver : BroadcastReceiver() {

 override fun onReceive(context: Context, intent: Intent) {
 val geofencingEvent = GeofencingEvent.fromIntent(intent)
 if (geofencingEvent?.hasError() == true) {
 Log.e("GeofenceReceiver", "Geofencing event has error: ${geofencingEvent.errorCode}")
 // Show user-facing error message
 showToast(context, "Geofencing error occurred: ${geofencingEvent.errorCode}")
 return
 }

 val geofenceTransition = geofencingEvent?.geofenceTransition
 val triggeringGeofences = geofencingEvent?.triggeringGeofences

 if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_ENTER) {
 Log.d("GeofenceReceiver", "Geofence Entered")
 // Handle enter event for each triggering geofence
 triggeringGeofences?.forEach { geofence ->
 startSession(context, geofence.requestId)
 }
 } else if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_EXIT) {
 Log.d("GeofenceReceiver", "Geofence Exited")
 // Handle exit event for each triggering geofence
 triggeringGeofences?.forEach { geofence ->
 endSession(context, geofence.requestId)
 }
 } else {
 Log.d("GeofenceReceiver", "Invalid transition type: $geofenceTransition")
 }
 }

 private fun startSession(context: Context, geofenceId: String) {
 val db = AppDatabase.getDatabase(context)
 CoroutineScope(Dispatchers.IO).launch {
 try {
 val now = System.currentTimeMillis()
 // Check if there's already an ongoing session for this geofence
 val ongoingSession = db.attendanceDao().getOngoingSession()
 if (ongoingSession == null) {
 db.attendanceDao().insertRecord(
 AttendanceRecord(date = now, timeIn = now, timeOut = null)
 )
 Log.d("GeofenceReceiver", "Session started for geofence: $geofenceId")
 showToast(context, "Entered geofenced area - session started")
 } else {
 Log.d("GeofenceReceiver", "Session already active for geofence: $geofenceId")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error starting session for geofence: $geofenceId", e)
 showToast(context, "Error starting session: ${e.message}")
 }
 }
 }

 private fun endSession(context: Context, geofenceId: String) {
 val db = AppDatabase.getDatabase(context)
 CoroutineScope(Dispatchers.IO).launch {
 try {
 val ongoingSession = db.attendanceDao().getOngoingSession()
 if (ongoingSession != null) {
 db.attendanceDao().updateRecord(
 ongoingSession.copy(timeOut = System.currentTimeMillis())
 )
 Log.d("GeofenceReceiver", "Session ended for geofence: $geofenceId")
 showToast(context, "Exited geofenced area - session ended")
 } else {
 Log.d("GeofenceReceiver", "No ongoing session to end for geofence: $geofenceId")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error ending session for geofence: $geofenceId", e)
 showToast(context, "Error ending session: ${e.message}")
 }
 }
 }

 private fun showToast(context: Context, message: String) {
 // Use main thread for Toast
 CoroutineScope(Dispatchers.Main).launch {
 Toast.makeText(context, message, Toast.LENGTH_LONG).show()
 }
 }
}

class GeofenceManager(private val context: Context) {

 private val geofencingClient = LocationServices.getGeofencingClient(context)
 private val TAG = "GeofenceManager"

 fun addGeofence(
 id: String,
 latitude: Double,
 longitude: Double,
 radius: Float,
 pendingIntent: PendingIntent
 ) {
 if (ActivityCompat.checkSelfPermission(
 context,
 Manifest.permission.ACCESS_FINE_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Log.w(TAG, "Fine location permission not granted.")
 showToast("Location permission not granted")
 return
 }

 // For Android 10+ (API 29+), background location permission is also required
 if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
 if (ActivityCompat.checkSelfPermission(
 context,
 Manifest.permission.ACCESS_BACKGROUND_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Log.w(TAG, "Background location permission not granted for Android 10+.")
 showToast("Background location permission required for geofencing")
 return
 }
 }

 val geofence = Geofence.Builder()
 .setRequestId(id)
 .setCircularRegion(latitude, longitude, radius)
 .setExpirationDuration(Geofence.NEVER_EXPIRE)
 .setTransitionTypes(Geofence.GEOFENCE_TRANSITION_ENTER or Geofence.GEOFENCE_TRANSITION_EXIT)
 .setLoiteringDelay(60000) // 1 minute delay before triggering dwell events (if needed)
 .build()

 val geofencingRequest = GeofencingRequest.Builder()
 .setInitialTrigger(GeofencingRequest.INITIAL_TRIGGER_ENTER)
 .addGeofence(geofence)
 .build()

 // Remove existing geofence before adding new one to prevent conflicts
 removeGeofence(pendingIntent) { success ->
 geofencingClient.addGeofences(geofencingRequest, pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence added successfully for ID: $id")
 showToast("Geofence activated for $id")
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to add geofence for ID: $id", exception)
 showToast("Failed to activate geofence: ${exception.message}")
 }
 }
 }

 fun removeGeofence(pendingIntent: PendingIntent, callback: ((Boolean) -> Unit)? = null) {
 geofencingClient.removeGeofences(pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence removed successfully.")
 callback?.invoke(true)
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to remove geofence.", exception)
 callback?.invoke(false)
 }
 }

 private fun showToast(message: String) {
 CoroutineScope(Dispatchers.Main).launch {
 Toast.makeText(context, message, Toast.LENGTH_LONG).show()
 }
 }
}
```

### 2. Fix PendingIntent Creation Inconsistency

