 modifier = modifier
 .fillMaxSize()
 .padding(16.dp),
 verticalArrangement = Arrangement.spacedBy(16.dp),
 horizontalAlignment = Alignment.CenterHorizontally
 ) {
 if (sessionInProgress) {
 Spacer(modifier = Modifier.weight(0.1f))
