# The setting is particularly useful for tweaking memory settings.
org.gradle.jvmargs=-Xmx2048m -Dfile.encoding=UTF-8 -XX:+UseG1GC -XX:+UseStringDeduplication -Dkotlin.compiler.execution.strategy=daemon
# When configured, Gradle will run in incubating parallel mode.
