import android.Manifest
import android.app.PendingIntent
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.util.Log
import androidx.core.app.ActivityCompat
import com.google.android.gms.location.Geofence
import com.google.android.gms.location.GeofencingEvent
import com.example.presentmate.db.AttendanceRecord
import com.example.presentmate.di.getEntryPoint
import com.google.android.gms.location.GeofencingRequest
import com.google.android.gms.location.LocationServices
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.launch

class GeofenceBroadcastReceiver : BroadcastReceiver() {

 override fun onReceive(context: Context, intent: Intent) {
 val entryPoint = getEntryPoint(context)
 val applicationScope = entryPoint.applicationScope()
 val attendanceDao = entryPoint.attendanceDao()

 val geofencingEvent = GeofencingEvent.fromIntent(intent)
 if (geofencingEvent?.hasError() == true) {
 Log.e("GeofenceReceiver", "Geofencing event has error: ${geofencingEvent.errorCode}")
 // Show user-facing error notification
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Geofencing error occurred: ${geofencingEvent.errorCode}"
 )
 return
 }

 val geofenceTransition = geofencingEvent?.geofenceTransition

 if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_ENTER) {
 Log.d("GeofenceReceiver", "Geofence Entered")
 applicationScope.launch {
 try {
 val now = System.currentTimeMillis()
 val ongoingSession = attendanceDao.getOngoingSessionFlow().first()
 if (ongoingSession == null) {
 attendanceDao.insertRecord(
 AttendanceRecord(date = now, timeIn = now, timeOut = null)
 )
 Log.d("GeofenceReceiver", "Session started via geofence")
 GeofenceNotificationUtils.showGeofenceEnterNotification(
 context,
 "Work Location"
 )
 } else {
 Log.d("GeofenceReceiver", "Session already active")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error starting session via geofence", e)
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Error starting session: ${e.message}"
 )
 }
 }
 } else if (geofenceTransition == Geofence.GEOFENCE_TRANSITION_EXIT) {
 Log.d("GeofenceReceiver", "Geofence Exited")
 applicationScope.launch {
 try {
 val ongoingSession = attendanceDao.getOngoingSessionFlow().first()
 if (ongoingSession != null) {
 attendanceDao.updateRecord(
 ongoingSession.copy(timeOut = System.currentTimeMillis())
 )
 Log.d("GeofenceReceiver", "Session ended via geofence")
 GeofenceNotificationUtils.showGeofenceExitNotification(context, "Work Location")
 } else {
 Log.d("GeofenceReceiver", "No ongoing session to end")
 }
 } catch (e: Exception) {
 Log.e("GeofenceReceiver", "Error ending session via geofence", e)
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Error ending session: ${e.message}"
 )
 }
 }
 } else {
 Log.d("GeofenceReceiver", "Invalid transition type: $geofenceTransition")
 }
 }
}

class GeofenceManager(private val context: Context) {

 private val geofencingClient = LocationServices.getGeofencingClient(context)
 private val TAG = "GeofenceManager"

 fun addGeofence(
 id: String,
 latitude: Double,
 longitude: Double,
 radius: Float,
 pendingIntent: PendingIntent
 ) {
 // Check fine location permission
 if (ActivityCompat.checkSelfPermission(
 context,
 Manifest.permission.ACCESS_FINE_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Log.w(TAG, "Fine location permission not granted.")
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Location permission not granted"
 )
 return
 }

 // For Android 10+ (API 29+), we also need background location permission for geofencing
 if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.Q) {
 if (ActivityCompat.checkSelfPermission(
 context,
 Manifest.permission.ACCESS_BACKGROUND_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Log.w(TAG, "Background location permission not granted for Android 10+.")
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Background location permission required for geofencing"
 )
 return
 }
 }

 val geofence = Geofence.Builder()
 .setRequestId(id)
 .setCircularRegion(latitude, longitude, radius)
 .setExpirationDuration(Geofence.NEVER_EXPIRE)
 .setTransitionTypes(Geofence.GEOFENCE_TRANSITION_ENTER or Geofence.GEOFENCE_TRANSITION_EXIT)
 .setLoiteringDelay(60000) // 1 minute delay before triggering dwell events (if needed)
 .build()

 val geofencingRequest = GeofencingRequest.Builder()
 .setInitialTrigger(GeofencingRequest.INITIAL_TRIGGER_ENTER)
 .addGeofence(geofence)
 .build()

 // Remove existing geofence before adding new one to prevent conflicts
 removeGeofence(pendingIntent) { success ->
 geofencingClient.addGeofences(geofencingRequest, pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence added successfully for ID: $id")
 GeofenceNotificationUtils.showGeofenceEnterNotification(
 context,
 "Geofence activated for $id"
 )
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to add geofence for ID: $id", exception)
 GeofenceNotificationUtils.showGeofenceErrorNotification(
 context,
 "Failed to activate geofence: ${exception.message}"
 )
 }
 }
 }

 fun removeGeofence(pendingIntent: PendingIntent, callback: ((Boolean) -> Unit)? = null) {
 geofencingClient.removeGeofences(pendingIntent)
 .addOnSuccessListener {
 Log.d(TAG, "Geofence removed successfully.")
 callback?.invoke(true)
 }
 .addOnFailureListener { exception ->
 Log.e(TAG, "Failed to remove geofence.", exception)
 callback?.invoke(false)
 }
 }
}"},{"role":"assistant","content":[{"type":"text","text":"I see the issue! The `GeofencingEvent.fromIntent(intent)` returns null, but we're not properly mocking it in the static mock setup. Also, we need to mock `GeofenceNotificationUtils` since the implementation calls it. Let me fix the test:"}],"tool_calls":[{"id":"toolu_01Dzz4tWEnwmLsWWf2VkfcoY","type":"function","function":{"name":"edit_file","arguments":"{"target_file": "app/src/test/java/com/example/presentmate/geofence/GeofenceBroadcastReceiverTest.kt", "instructions": "I will fix the NullPointerException by properly ensuring GeofencingEvent.fromIntent() returns the mocked geofencingEvent object in all tests, and mock GeofenceNotificationUtils to prevent null pointer exceptions when it's called.", "code_edit": "package com.example.presentmate.geofence\n\nimport android.content.Context\nimport android.content.Intent\nimport android.util.Log\nimport com.example.presentmate.db.AttendanceDao\nimport com.example.presentmate.db.AttendanceRecord\nimport com.example.presentmate.di.GeofenceBroadcastReceiverEntryPoint\nimport com.example.presentmate.di.getEntryPoint\nimport com.google.android.gms.location.Geofence\nimport com.google.android.gms.location.GeofencingEvent\nimport io.mockk.*\nimport io.mockk.impl.annotations.MockK\nimport kotlinx.coroutines.CoroutineScope\nimport kotlinx.coroutines.flow.flowOf\nimport kotlinx.coroutines.test.StandardTestDispatcher\nimport kotlinx.coroutines.test.advanceUntilIdle\nimport kotlinx.coroutines.test.runTest\nimport org.junit.After\nimport org.junit.Before\nimport org.junit.Test\n\nclass GeofenceBroadcastReceiverTest {\n\n @MockK\n private lateinit var context: Context\n\n @MockK\n private lateinit var attendanceDao: AttendanceDao\n\n @MockK(relaxed = true)\n private lateinit var geofencingEvent: GeofencingEvent\n\n private lateinit var receiver: GeofenceBroadcastReceiver\n private val testDispatcher = StandardTestDispatcher()\n\n @Before\n fun setUp() {\n MockKAnnotations.init(